var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"공군 기술 연구소 임시 선착장\\n델타 세븐 기함, 엔터프라이즈\\n감찰부대 기습 380초 전","JPN":"空軍技術研究所の臨時船着き場\\nデルタセブンの旗艦、エンタープライズ\\n監察部隊の奇襲まであと380秒","ENG":"[[","TWN":"空軍技術研究所 臨時機庫\\n第七三角洲部隊艦船 企業號\\n監察組偷襲前380秒","THA":"ลานจอดชั่วคราวห้องวิจัยกองทัพอากาศ\\nเอ็นเตอร์ไพรส์ ยานรบหลักของเดลต้าเซเว่น\\n380 วินาทีก่อนหน่วยตรวจสอบจะโจมตีอย่างไม่คาดคิด","VTN":"Căn Cứ Tạm Thời Phòng Nghiên Cứu Lực Lượng Không Quân,\\nTàu Đô Đốc Delta Seven, Enterprise \\n380 giây trước cuộc tấn công bất ngờ của Inspection Corps.","SCN":"空军研究所临时船坞\\n德尔塔部队旗舰，企业号\\n监察部队突袭380秒前","DEU":"Temporäres Dock des Technischen Forschungsinstituts der Luftwaffe\\nDelta Seven Flaggschiff, Enterprise\\n380 Sekunden vor dem Überraschungsangriff des Inspektionstrupps","FRA":"Laboratoire de recherche de l'Armée de l'Air, Passerelle temporaire\\nVaisseau amiral du Delta Seven Enterprise\\n380 s avant l'attaque du corps d'inspection"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 엔터프라이즈의 개장 작업은 어떻게 되어 가고 있지?","JPN":"カイル、エンタープライズの改装作業はどうなっている？","ENG":"Kyle, how are the remodeling on the Enterprise going?","TWN":"凱爾，企業號的改裝作業進行得如何？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기용할 수 있는 인원을 모두 투입한 상태입니다.","JPN":"動員できる人員をすべて投入している状態です。","ENG":"I have deployed all the personnel that I can appoint for it.","TWN":"已投入所有可用人力。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시간은 촉박하지만…… 곧 작전 투입은 가능할 겁니다.","JPN":"時間が差し迫っていますが……もうすぐ作戦投入はできるかと。","ENG":"We are short on time... But she should be ready for operations deployment soon.","TWN":"時間是有點急迫……不過應該很快就可以加入作戰。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋아, 전력 충원은?","JPN":"よろしい、戦力の補充は？","ENG":"Good. What about the crew?","TWN":"很好，那戰力增員呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님 지시대로 테라사이드 전역에 참전했던 인원들 위주로 소집했습니다.","JPN":"中将の指示どおり、テラサイドの戦域に参戦した者を優先して招集しました。","ENG":"We have been drafting mainly from those who participated in the Terraside battle, as ordered by the Lieutenant General.","TWN":"已經按照中將的指示，針對參加過特拉賽德戰役的人力進行招募。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다만 경찰청에서 파견 나온 분들과 제인 도우라는 용병은 연락이 닿지 않더군요.","JPN":"ただ警察庁から派遣された方々と、ジェーン・ドウという傭兵は連絡がつきませんでした。","ENG":"However, we have not been able to contact those dispatched from the police agency and the mercenary named Jane Doe.","TWN":"不過還沒能和警察局派來的人，與那個叫作珍妮·多伊的傭兵連絡上。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……아쉽지만 어쩔 수 없지.","JPN":"……残念だが仕方ない。","ENG":"...That’s unfortunate, but I guess it can’t be helped.","TWN":"……真可惜，但也沒辦法。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 지금은 한 명이라도 믿을 수 있는 인원이 필요해.","JPN":"しかし今は一人でも信頼できる者が必要だ。","ENG":"Regardless, we need at least one person that we can trust.","TWN":"不過現在需要盡可能召聚信得過的人力。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 차라리 본국에 증원 병력을 요청하는 게 낫지 않겠습니까?","JPN":"ならいっそのこと本国へ兵力の増員を要請した方がよろしいのではないでしょうか。","ENG":"In that case, wouldn’t it be better to request reinforcements from HQ?","TWN":"既然如此，那何不乾脆向國家請求增加兵力呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"갑자기 왜 그렇게 보안에 신경을 쓰시는 건지 모르겠습니다.","JPN":"いきなり保安にこだわる理由がわかりません。","ENG":"I don’t understand why we suddenly pay extra attention to security.","TWN":"我不知道為何突然加強戒備。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소집한 인원들은 물론 믿을 수 있는 자들이지만 솔직히 전력으로서 도움이 될 지는……","JPN":"招集した者たちはもちろん信頼できますが、正直戦力として役に立つかは……","ENG":"Of course, we can trust the people that we drafted. But to be honest, I’m not sure how much they'll be helpful in the battlefield...","TWN":"召集起來的這些人當然是信得過沒錯，但老實說，是否能成為戰力……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"더구나 그 룩이라는 소녀는 의심스럽기까지 합니다.","JPN":"それに、あのルークという少女は疑わしいです。","ENG":"Moreover, the girl named Rook is suspicious.","TWN":"而且，那個叫作城堡的女孩，我對她還有些懷疑。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"중장님께서 데려오시긴 했지만 어떤 기록에서도 그녀에 대한 자료를 찾아볼 수 없었습니다.","JPN":"中将が連れてこられたことは知っていますが、どの記録にも彼女に関する資料は見当たりません。","ENG":"Although you brought her here, I couldn’t find any information about her in all of our records.","TWN":"雖然人是中將帶來的，但在紀錄上完全找不到她的相關資料。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……잠재적 아군에게서 지원받은 인원이다.","JPN":"……潜在的な味方が支援してくれた者だ。","ENG":"...She’s support personnel sent by a potential ally.","TWN":"……她是潛在盟軍提供的人力。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"일종의 연락책이라고 생각하면 될 거야. 그녀에 대해서는 내가 보증하지.","JPN":"一種の連絡役と考えればいい。彼女については私が保証しよう。","ENG":"Think of her as a contact. I can vouch for her.","TWN":"就把她想成是雙方的橋樑吧，她的部分我可以做擔保。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};